INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '68e67131-0d58-4de8-823a-b909a57e67f8',
  '00000000-0000-0000-0000-000000000001',
  $escape$ipfs — Indexing Blockchain Events with The Graph Subgraphs$escape$,
  $escape$The Graph is a powerful tool for indexing blockchain events, and when combined with ipfs, it enables decentralized data storage and querying. By creating a subgraph, you can define the data you want to index from the blockchain, and then use GraphQL queries to retrieve it. ipfs provides a decentralized storage solution for the indexed data, allowing for censorship-resistant and persistent data storage. To get started, you'll need to install the `@graphprotocol/graph-cli` package and initialize a new subgraph project. Then, define your subgraph's schema and data sources using the `schema.graphql` and `subgraph.yaml` files.$escape$,
  $escape$const { createClient } = require('@ipfs/http-client');
const ipfs = createClient('https://ipfs.infura.io:5001/api/v0');
const graphClient = new TheGraphClient('https://api.thegraph.com/subgraphs/name/your-subgraph');
const query = `{\n  events {\n    id\n    blockNumber\n  }\n}`;
graphClient.query(query).then((data) => console.log(data));$escape$,
  $escape$javascript$escape$,
